"use strict";(self.webpackChunkauctions_for_woocommerce_doc=self.webpackChunkauctions_for_woocommerce_doc||[]).push([[6473],{2066(e,t,r){r.r(t),r.d(t,{comp:()=>a,data:()=>o});var n=r(641);const i={},a=(0,r(6262).A)(i,[["render",function(e,t){return(0,n.uX)(),(0,n.CE)("div",null,[...t[0]||(t[0]=[(0,n.Fv)('<h1 id="single-auction-page" tabindex="-1"><a class="header-anchor" href="#single-auction-page"><span>Single Auction Page</span></a></h1><p>The customer-facing page for any individual auction. Lives at the linked product&#39;s permalink (<code>/product/{slug}/</code>).</p><p><img src="/auctions-for-woocommerce/images/screenshots/auction-type-standard-1.png" alt="Single auction page — gallery, type badge, current price, time remaining, reserve indicator, anti-snipe note, bid form, Buy Now and Proxy Bidding"></p><h2 id="components" tabindex="-1"><a class="header-anchor" href="#components"><span>Components</span></a></h2><p>A standard auction page renders:</p><ol><li><a href="#gallery">Image gallery</a></li><li><a href="#badge">Auction badge</a></li><li><a href="#title">Title + auction type label</a></li><li><a href="#price">Current price + bid count</a></li><li><a href="#countdown">Countdown timer</a></li><li><a href="#reserve-indicator">Reserve indicator</a></li><li><a href="#bid-form">Bid form</a></li><li><a href="#buy-now">Buy Now button</a> (if set)</li><li><a href="#watchers">Watchers count + Watch button</a></li><li><a href="#bid-history">Bid history</a></li><li><a href="#description">Description</a></li><li><a href="#condition">Item condition</a></li><li><a href="#shipping">Shipping estimator</a></li><li><a href="#share">Share buttons</a></li><li><a href="#comparison">Comparison checkbox</a></li><li><a href="#contact-seller">Contact seller</a></li></ol><h2 id="gallery" tabindex="-1"><a class="header-anchor" href="#gallery"><span>Gallery</span></a></h2><p>Standard WooCommerce product gallery with multiple images, click-to-lightbox / full-screen, hover-zoom (configurable in <a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a>) and touch-swipe on mobile.</p><h2 id="badge" tabindex="-1"><a class="header-anchor" href="#badge"><span>Badge</span></a></h2><p>Displayed top-left of the gallery:</p><table><thead><tr><th>Badge</th><th>When</th></tr></thead><tbody><tr><td><strong>Live</strong></td><td>Auction is currently active</td></tr><tr><td><strong>Ending Soon</strong></td><td>Inside the urgency window you configured</td></tr><tr><td><strong>New</strong></td><td>Created within the last 24 hours</td></tr><tr><td><strong>Hot</strong></td><td>A burst of bids in the last hour above the hot-auction threshold</td></tr><tr><td><strong>Featured</strong></td><td>Admin-marked featured</td></tr></tbody></table><p>Multiple badges can stack. Customisable via <a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a>.</p><h2 id="title" tabindex="-1"><a class="header-anchor" href="#title"><span>Title</span></a></h2><p>Shows the product title (linked), the auction type label (&quot;Standard auction&quot; / &quot;Reverse auction&quot; / etc.) and — on multi-vendor stores — the seller name.</p><h2 id="price" tabindex="-1"><a class="header-anchor" href="#price"><span>Price</span></a></h2><table><thead><tr><th>Element</th><th>Shown as</th></tr></thead><tbody><tr><td>Current price</td><td>The highest valid bid so far</td></tr><tr><td>Bid count</td><td>Total bids placed</td></tr><tr><td>Suggested next bid</td><td>Current price plus the configured increment</td></tr></tbody></table><p>The current price updates live via polling (no page reload).</p><h2 id="countdown" tabindex="-1"><a class="header-anchor" href="#countdown"><span>Countdown</span></a></h2><p>A real-time countdown to the auction end. The timer is colour-coded so urgency is visible at a glance:</p><table><thead><tr><th>State</th><th>Colour</th><th>Threshold</th></tr></thead><tbody><tr><td>Default</td><td>charcoal / dark</td><td>More than the yellow stop</td></tr><tr><td>Yellow</td><td>amber</td><td>Final hour (default)</td></tr><tr><td>Orange</td><td>orange</td><td>Final 10 minutes (default)</td></tr><tr><td>Red</td><td>red, pulsing</td><td>Final 2 minutes (default)</td></tr></tbody></table><p>Thresholds are configurable in <strong>Settings → General</strong>. The countdown re-syncs to server time every poll cycle to prevent client-clock drift.</p><h2 id="reserve-indicator" tabindex="-1"><a class="header-anchor" href="#reserve-indicator"><span>Reserve indicator</span></a></h2><p>Shows next to the current price when a reserve is set:</p><table><thead><tr><th>Text</th><th>When</th></tr></thead><tbody><tr><td>&quot;Reserve not met&quot;</td><td>Current price is below the reserve</td></tr><tr><td>&quot;Reserve met ✓&quot; (green)</td><td>Current price has reached or passed the reserve</td></tr><tr><td>(hidden)</td><td>No reserve was set</td></tr></tbody></table><p><a href="/reserve-buy-now.html#reserve" target="_blank" rel="noopener noreferrer">Reserve detail →</a></p><h2 id="bid-form" tabindex="-1"><a class="header-anchor" href="#bid-form"><span>Bid form</span></a></h2><p>The interactive bidding control. Three sub-modes depending on auction type:</p><h3 id="standard-reverse-sealed" tabindex="-1"><a class="header-anchor" href="#standard-reverse-sealed"><span>Standard / Reverse / Sealed</span></a></h3><ul><li>Amount input</li><li><strong>Place Bid</strong> button</li><li>Quick-bid buttons (+5%, +10%, +25%)</li><li>Bid confirmation modal (if enabled)</li></ul><h3 id="proxy" tabindex="-1"><a class="header-anchor" href="#proxy"><span>Proxy</span></a></h3><ul><li>Same as standard, plus an <strong>Auto-bid up to</strong> input for setting the maximum</li><li>Toggle: &quot;I want the system to auto-bid for me&quot;</li></ul><h3 id="penny" tabindex="-1"><a class="header-anchor" href="#penny"><span>Penny</span></a></h3><ul><li>Bid pack purchase widget (if no pack yet)</li><li><strong>Place 1 bid</strong> button (one click = one bid using one token)</li><li>Pack-remaining counter</li></ul><p>Logged-out users see the form replaced with a <strong>Sign in to bid</strong> button.</p><h2 id="buy-now" tabindex="-1"><a class="header-anchor" href="#buy-now"><span>Buy Now</span></a></h2><p>Optional &quot;skip the auction&quot; button next to the bid form. Adds the item to cart at the Buy Now price. <a href="/reserve-buy-now.html#buy-it-now" target="_blank" rel="noopener noreferrer">Buy Now reference →</a></p><h2 id="watchers" tabindex="-1"><a class="header-anchor" href="#watchers"><span>Watchers</span></a></h2><p>Below the bid form:</p><table><thead><tr><th>Element</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>Watchers count</strong></td><td>&quot;23 people watching&quot; — appears once a minimum threshold is reached</td></tr><tr><td><strong>Watch button</strong></td><td>Toggles watch state for this customer</td></tr></tbody></table><p><a href="/watchlist.html" target="_blank" rel="noopener noreferrer">Watchlist →</a>, <a href="/psychology.html#watchers" target="_blank" rel="noopener noreferrer">Psychology →</a></p><h2 id="bid-history" tabindex="-1"><a class="header-anchor" href="#bid-history"><span>Bid history</span></a></h2><p>A scrollable list of every bid on this auction.</p><table><thead><tr><th>Column</th><th>What it shows</th></tr></thead><tbody><tr><td>Bidder</td><td>Display name (masked when site-wide masking is on)</td></tr><tr><td>Amount</td><td>The bid amount</td></tr><tr><td>Type</td><td>Manual / proxy / quick / buy-now</td></tr><tr><td>Time</td><td>Friendly relative time (&quot;2 min ago&quot;)</td></tr></tbody></table><p>Display modes (configurable in <a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a>):</p><ul><li><strong>Inline</strong> — visible by default</li><li><strong>Accordion</strong> — collapsed; click to expand</li><li><strong>Hidden</strong> — not shown publicly</li></ul><h2 id="description" tabindex="-1"><a class="header-anchor" href="#description"><span>Description</span></a></h2><p>The standard WooCommerce product description.</p><h2 id="condition" tabindex="-1"><a class="header-anchor" href="#condition"><span>Condition</span></a></h2><p>Below the description:</p><blockquote><p><strong>Item condition:</strong> New / Like New / Used / Refurbished / For Parts</p></blockquote><p>Set on the auction itself in <a href="/admin-add-auction.html" target="_blank" rel="noopener noreferrer">Add / Edit Auction</a>.</p><h2 id="shipping" tabindex="-1"><a class="header-anchor" href="#shipping"><span>Shipping</span></a></h2><p>When enabled, the customer enters a destination postcode / country and gets an estimated shipping cost based on your WooCommerce shipping zones. Useful for buyers calibrating their max bid.</p><h2 id="share" tabindex="-1"><a class="header-anchor" href="#share"><span>Share</span></a></h2><p>Social share buttons (if enabled in <a href="/admin-design-studio.html" target="_blank" rel="noopener noreferrer">Design Studio</a>):</p><ul><li>Facebook, Twitter, WhatsApp, Pinterest, LinkedIn</li><li>Email</li><li>Copy link</li></ul><p><a href="/social-sharing.html" target="_blank" rel="noopener noreferrer">Social Sharing →</a></p><h2 id="comparison" tabindex="-1"><a class="header-anchor" href="#comparison"><span>Comparison</span></a></h2><p>Checkbox: <strong>Add to compare</strong>. Adds this auction to the customer&#39;s compare list (max 3 lots). <a href="/customer-overview.html#comparison" target="_blank" rel="noopener noreferrer">Comparison →</a></p><h2 id="contact-seller" tabindex="-1"><a class="header-anchor" href="#contact-seller"><span>Contact seller</span></a></h2><p>Button opens a modal with a subject and message field. The seller receives an email and an in-app badge. By default, messaging closes once the customer has placed a bid on the lot (prevents collusion). <a href="/customer-overview.html#messaging" target="_blank" rel="noopener noreferrer">Customer overview → Messaging</a></p><h2 id="live-updates" tabindex="-1"><a class="header-anchor" href="#live-updates"><span>Live updates</span></a></h2><p>The page polls in the background:</p><ul><li>Every 30 seconds (configurable) under normal conditions</li><li>Every 3 seconds in the last 2 minutes</li><li>Polling pauses for dormant auctions (no bids in the last 30 minutes)</li></ul><p>Refreshed on each poll: current price, bid count, time left, watchers count, &quot;Hot&quot; badge.</p><h2 id="live-confetti" tabindex="-1"><a class="header-anchor" href="#live-confetti"><span>Live confetti</span></a></h2><p>When the customer wins (auction closes with their bid leading), a confetti burst plays. Toggleable site-wide in <strong>Settings → General → Confetti on win</strong>.</p><h2 id="mobile" tabindex="-1"><a class="header-anchor" href="#mobile"><span>Mobile</span></a></h2><p>Single-column layout. Touch-friendly:</p><ul><li>Larger buttons (minimum 44 px tap targets)</li><li>Sticky bid form at the bottom on scroll</li><li>Slightly slower polling cadence to save battery</li></ul>',70)])])}]]),o=JSON.parse('{"path":"/customer-single-auction.html","title":"Single Auction Page","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"Components","slug":"components","link":"#components","children":[]},{"level":2,"title":"Gallery","slug":"gallery","link":"#gallery","children":[]},{"level":2,"title":"Badge","slug":"badge","link":"#badge","children":[]},{"level":2,"title":"Title","slug":"title","link":"#title","children":[]},{"level":2,"title":"Price","slug":"price","link":"#price","children":[]},{"level":2,"title":"Countdown","slug":"countdown","link":"#countdown","children":[]},{"level":2,"title":"Reserve indicator","slug":"reserve-indicator","link":"#reserve-indicator","children":[]},{"level":2,"title":"Bid form","slug":"bid-form","link":"#bid-form","children":[{"level":3,"title":"Standard / Reverse / Sealed","slug":"standard-reverse-sealed","link":"#standard-reverse-sealed","children":[]},{"level":3,"title":"Proxy","slug":"proxy","link":"#proxy","children":[]},{"level":3,"title":"Penny","slug":"penny","link":"#penny","children":[]}]},{"level":2,"title":"Buy Now","slug":"buy-now","link":"#buy-now","children":[]},{"level":2,"title":"Watchers","slug":"watchers","link":"#watchers","children":[]},{"level":2,"title":"Bid history","slug":"bid-history","link":"#bid-history","children":[]},{"level":2,"title":"Description","slug":"description","link":"#description","children":[]},{"level":2,"title":"Condition","slug":"condition","link":"#condition","children":[]},{"level":2,"title":"Shipping","slug":"shipping","link":"#shipping","children":[]},{"level":2,"title":"Share","slug":"share","link":"#share","children":[]},{"level":2,"title":"Comparison","slug":"comparison","link":"#comparison","children":[]},{"level":2,"title":"Contact seller","slug":"contact-seller","link":"#contact-seller","children":[]},{"level":2,"title":"Live updates","slug":"live-updates","link":"#live-updates","children":[]},{"level":2,"title":"Live confetti","slug":"live-confetti","link":"#live-confetti","children":[]},{"level":2,"title":"Mobile","slug":"mobile","link":"#mobile","children":[]}],"git":{},"filePathRelative":"customer-single-auction.md"}')}}]);